TEA-HACK.script:
{
    // 1. Create the glassy overlay and card
    const teaModal = document.createElement('div');
    teaModal.className = 'modal-overlay active';
    teaModal.style.zIndex = '9999';

    teaModal.innerHTML = `
        <div class="modal-card">
            <h2 class="modal-title">☕ Tea Injector</h2>
            <p class="modal-text">Enter the amount of tea clicks to inject into your save file:</p>
            <input type="number" id="teaHackInput" class="input" placeholder="e.g. 50000" style="width: 100%; margin-bottom: 20px; box-sizing: border-box;" />
            <br>
            <button class="btn" id="injectBtn">Inject Tea</button>
            <button class="btn" id="cancelBtn" style="background: transparent; border: 1px solid rgba(255,255,255,0.2); margin-left: 10px;">Cancel</button>
        </div>
    `;

    // 2. Add it to the screen
    document.body.appendChild(teaModal);

    // 3. Make the "Inject" button work
    document.getElementById('injectBtn').onclick = () => {
        const amount = parseInt(document.getElementById('teaHackInput').value) || 0;

        // Grab their current score, add the new amount, and save it back
        let currentScore = parseInt(localStorage.getItem('tea_local_score')) || 0;
        localStorage.setItem('tea_local_score', currentScore + amount);

        // Remove our custom modal
        teaModal.remove();

        // Trigger the built-in success popup
        document.getElementById('popupText').textContent = "System Override: " + amount.toLocaleString() + " tea clicks added!";
        document.getElementById('popupModal').classList.add('active');
    };

    // 4. Make the "Cancel" button work
    document.getElementById('cancelBtn').onclick = () => {
        teaModal.remove();
    };
}
